// ============================================================
// 節點：指令解析（規則式）
// ============================================================
const CONFIG = {
  warehouses: ['TAO1','TAO3','TAO4','TAO5','TAO6','TAO7','TAO10'],
  intentKeywords: [
    { keywords: ['病假統計'], intent: 'sick_leave_stats' },
    { keywords: ['請假統計'], intent: 'leave_stats' },
    { keywords: ['請假狀況','請假'], intent: 'leave_status' },
    { keywords: ['出勤人員','出勤明細','出勤報表'], intent: 'attendance_detail' },
    { keywords: ['出勤統計'], intent: 'attendance_stats' },
  ],
  leaveTypeKeywords: [
    { keywords: ['病假','病'], leaveType: '病假' },
    { keywords: ['事假','事'], leaveType: '事假' },
    { keywords: ['特休','特'], leaveType: '特休' },
    { keywords: ['曠職','曠'], leaveType: '曠職' },
  ],
};
const query = ($input.first().json.body?.query || '').trim();
if (!query) return [{ json: { success:false, error:'請提供查詢指令', hint:'範例：4/2請假狀況' } }];
function parseDate(q) {
  const yr = new Date().getFullYear();
  let m = q.match(/(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})/);
  if (m) return `${m[1]}-${String(m[2]).padStart(2,'0')}-${String(m[3]).padStart(2,'0')}`;
  m = q.match(/(\d{1,2})[\/-](\d{1,2})/);
  if (m) return `${yr}-${String(m[1]).padStart(2,'0')}-${String(m[2]).padStart(2,'0')}`;
  return null;
}
function parseIntent(q) { for (const r of CONFIG.intentKeywords) for (const k of r.keywords) if (q.includes(k)) return r.intent; return 'attendance_detail'; }
function parseWH(q) { if (/全部倉|所有倉|全倉/.test(q)) return CONFIG.warehouses.slice(); const f=[]; for (const w of CONFIG.warehouses) if (q.toUpperCase().includes(w)) f.push(w); return f.length?f:CONFIG.warehouses.slice(); }
function parseLT(q) { for (const r of CONFIG.leaveTypeKeywords) for (const k of r.keywords) if (q.includes(k)) return r.leaveType; return ''; }
const date = parseDate(query);
if (!date) return [{ json: { success:false, error:'無法解析日期', hint:'支援：4/2、2026/4/2', originalQuery:query } }];
const intent = parseIntent(query);
return [{ json: { success:true, parsed: { intent, date, warehouse:parseWH(query), leaveType:parseLT(query), needReport:['sick_leave_stats','leave_stats','attendance_stats'].includes(intent) }, originalQuery:query } }];

// ============================================================
// 節點：組裝讀取參數
// ============================================================
const CONFIG = {
  spreadsheetMap: {
    'TAO1':'1_bhGQdx0YH7lsqPFEq5___6_Nwq_gbelJmIHv0bmaIE',
    'TAO3':'1cffI2jIVZA1uSiAyaLLXXgPzDByhy87xznaN85O7wEE',
    'TAO4':'1tVxQbV0298fn2OXWAF0UqZa7FLbypsatciatxs4YVTU',
    'TAO5':'1jzVXC6gt36hJtlUHoxtTzZLMNj4EtTsd4k8eNB1bdiA',
    'TAO6':'1wwPLSLjl2abfM_OMdTNI9PoiPKo3waCV_y0wmx2DxAE',
    'TAO7':'16nGCqRO8DYDm0PbXFbdt-fiEFZCXxXjlOWjKU67p4LY',
    'TAO10':'1y0w49xdFlHvcVtgtG8fq6zdrF26y8j7HMFh5ujzUyR4',
  },
  intentSheetType: { 'leave_status':'leave','sick_leave_stats':'leave','leave_stats':'leave','attendance_detail':'work','attendance_stats':'work' },
  sheetKeywords: { leave:['班表','出勤記錄','假況'], work:['出勤時數','出勤時間','工時'] },
};
const prev = $('指令解析').first().json;
const p = prev.parsed;
const st = CONFIG.intentSheetType[p.intent]||'leave';
const results = [];
for (const wh of p.warehouse) {
  const sid = CONFIG.spreadsheetMap[wh]; if (!sid) continue;
  results.push({ json: { warehouse:wh, spreadsheetId:sid, sheetType:st, sheetKeywords:CONFIG.sheetKeywords[st], intent:p.intent, date:p.date, leaveType:p.leaveType, needReport:p.needReport, originalQuery:prev.originalQuery } });
}
return results;

// ============================================================
// 節點：解析分頁，組裝資料 URL（月份感知）
// ============================================================
const CONFIG = { sheetKeywords: { leave:['班表','出勤記錄','假況'], work:['出勤時數','出勤時間','工時'] } };
let prev; try { prev = $('組裝讀取參數').first().json; } catch(e) { prev = $input.first().json; }
const meta = $input.first().json;
const wh = prev.warehouse, sid = prev.spreadsheetId, st = prev.sheetType;
const kw = CONFIG.sheetKeywords[st]||CONFIG.sheetKeywords.leave;
if (meta.error || !meta.sheets) {
  return [{ json: { ...prev, allSheetNames:[], warning:`${wh} 無法取得分頁`, dataUrl:'', success:false } }];
}
const names = meta.sheets.map(s=>s.properties.title);
const queryMonth = prev.date ? parseInt(prev.date.split('-')[1]) : 0;
const monthStr = queryMonth ? `${queryMonth}月` : '';
let target = null, warning = null;
if (monthStr) {
  for (const k of kw) { const f=names.find(n=>n.includes(k)&&n.includes(monthStr)); if(f){target=f;break;} }
}
if (!target) {
  for (const k of kw) { const f=names.find(n=>n.includes(k)); if(f){target=f;break;} }
}
if (!target) { target=names[0]||'Sheet1'; warning=`${wh} 找不到含 [${kw.join(',')}] 的分頁，使用「${target}」`; }
return [{ json: { ...prev, sheetName:target, allSheetNames:names, warning, dataUrl:`http://localhost:3456/sheets/data?spreadsheetId=${sid}&sheetName=${encodeURIComponent(target)}`, success:true } }];

// ============================================================
// 節點：資料標準化
// ============================================================
const CONFIG = {
  workFieldMapping: {
    date:['日期','Date'], department:['組別','部門','Department','組','Group'],
    shift:['班別','Shift','班次'], name:['姓名','Name','員工姓名'],
    workHours:['工作總時數','工時','Hours','總工時'],
    overtimeHours:['加班總時數','OvertimeHours','加班時數','加班'],
    note:['備註','Note','Remark'], attendanceStatus:['出勤狀態','Status'],
    leaveType:['假況','請假','LeaveType','假別'],
  },
  leaveStatusMapping: {
    '病假':'病假','病':'病假','事假':'事假','事':'事假',
    '特休':'特休','特':'特休','曠職':'曠職','曠':'曠職',
    '出勤':'出勤','正常':'出勤','休假':'休假','休':'休假',
    '公假':'公假','公':'公假','產假':'產假','喪假':'喪假','婚假':'婚假','例':'例假','例假':'例假','例休':'例休','未':'未到','離':'離職','離職':'離職','下休(事)':'事假','下休(特休)':'特休','下休(曠)':'曠職','病(無薪)':'病假','無薪病假':'病假',
  },
  leaveDateStartCol: 7,
};
let prev; try { prev=$('解析分頁並組裝URL').first().json; } catch(e) { prev={}; }
const api = $input.first().json;
const wh=prev.warehouse||'', st=prev.sheetType||'work', sn=prev.sheetName||'';
const allSN=prev.allSheetNames||[], date=prev.date||'', intent=prev.intent||'';
const lt=prev.leaveType||'', nr=prev.needReport||false, oq=prev.originalQuery||'';
const pw=prev.warning||null;
if (api.error||!api.values) return [{ json:{warehouse:wh,sheetType:st,sheetName:sn,allSheetNames:allSN,date,intent,leaveType:lt,needReport:nr,originalQuery:oq,warning:pw,rows:[],totalRows:0,success:false,error:`${wh}「${sn}」無資料`} }];
const hdr=api.values[0]||[], raw=api.values.slice(1);
function fc(h,a){for(const x of a){const i=h.findIndex(z=>z&&z.trim()===x);if(i!==-1)return i;}return -1;}
function ns(v){if(!v||v.trim()==='')return{status:'',ok:true};const lv=v.trim().toLowerCase();for(const[k,m]of Object.entries(CONFIG.leaveStatusMapping))if(lv===k.toLowerCase())return{status:m,ok:true};return{status:v.trim(),ok:false};}
let rows=[];
if(st==='work'){
  const cm={}; for(const[f,a]of Object.entries(CONFIG.workFieldMapping))cm[f]=fc(hdr,a);
  for(const r of raw){const g=f=>{const i=cm[f];return i>=0&&r[i]!==undefined?String(r[i]).trim():'';};
    const si=ns(g('attendanceStatus')||g('leaveType'));
    rows.push({date:g('date'),department:g('department'),shift:g('shift'),name:g('name'),workHours:g('workHours'),overtimeHours:g('overtimeHours'),attendanceStatus:si.status,leaveType:si.status,note:g('note'),warehouse:wh,...(!si.ok?{unresolvedStatus:true}:{})});}
}else{
  const dsc=CONFIG.leaveDateStartCol;
  const ni=fc(hdr,['姓名','Name','員工姓名']),di=fc(hdr,['組別','部門','Department','組']),si=fc(hdr,['班別','Shift','班次']);
  const dh=hdr.slice(dsc);
  for(const r of raw){const pn=ni>=0?String(r[ni]||'').trim():'';const dp=di>=0?String(r[di]||'').trim():'';const sh=si>=0?String(r[si]||'').trim():'';
    if(!pn)continue;
    for(let i=0;i<dh.length;i++){const cv=r[dsc+i];if(cv===undefined||cv===null||String(cv).trim()==='')continue;const s=ns(String(cv));
      rows.push({date:dh[i]?String(dh[i]).trim():'',department:dp,shift:sh,name:pn,workHours:'',overtimeHours:'',attendanceStatus:s.status,leaveType:s.status,note:'',warehouse:wh,...(!s.ok?{unresolvedStatus:true}:{})});}}
}
return [{json:{warehouse:wh,sheetType:st,sheetName:sn,allSheetNames:allSN,date,intent,leaveType:lt,needReport:nr,originalQuery:oq,warning:pw,rows,totalRows:rows.length,success:true}}];

// ============================================================
// 節點：合併所有倉別資料
// ============================================================
const all=$input.all(), mr=[], wn=[], er=[];
let date='',intent='',lt='',nr=false,oq=''; const wl=[];
for(const it of all){const d=it.json;if(!date)date=d.date;if(!intent)intent=d.intent;if(!lt)lt=d.leaveType;if(!nr)nr=d.needReport;if(!oq)oq=d.originalQuery;
  wl.push(d.warehouse);if(d.warning)wn.push(d.warning);if(!d.success){er.push(d.error||`${d.warehouse} 失敗`);continue;}if(d.rows?.length)mr.push(...d.rows);}
return [{json:{date,intent,leaveType:lt,needReport:nr,originalQuery:oq,warehouses:wl,rows:mr,totalRows:mr.length,warnings:wn.length?wn:undefined,errors:er.length?er:undefined,success:er.length===0}}];

// ============================================================
// 節點：查詢與統計（含人員明細）
// ============================================================
const AV=['出勤','正常',''];
const d=$input.first().json;
const{date,intent,leaveType:lt,originalQuery:oq,rows,warehouses:wh,warnings,errors}=d;
function md(rd,td){if(!rd||!td)return false;rd=String(rd).trim();td=String(td).trim();if(rd===td)return true;const p=td.split('-');if(p.length!==3)return false;const[tY,tM,tD]=p.map(Number);let m=rd.match(/^(\d{1,2})[\/-](\d{1,2})$/);if(m)return+m[1]===tM&&+m[2]===tD;m=rd.match(/^(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})$/);if(m)return+m[1]===tY&&+m[2]===tM&&+m[3]===tD;return false;}
function buildDetail(list) {
  const grouped = {};
  for (const r of list) {
    const lt = r.leaveType || r.attendanceStatus || '未分類';
    if (!grouped[lt]) grouped[lt] = [];
    grouped[lt].push(r);
  }
  const lines = [];
  for (const [type, people] of Object.entries(grouped)) {
    lines.push(`\n【${type}】${people.length} 人`);
    for (const p of people) {
      const parts = [p.warehouse, p.department, p.shift, p.name].filter(Boolean);
      lines.push(`  ${parts.join(' / ')}`);
    }
  }
  return lines.join('\n');
}
const df=rows.filter(r=>md(r.date,date));
let res={};
switch(intent){
case'leave_status':{const lr=df.filter(r=>{const s=r.attendanceStatus||r.leaveType||'';return s&&!AV.includes(s);});const fr=lt?lr.filter(r=>(r.leaveType||r.attendanceStatus)===lt):lr;
  const detail=buildDetail(fr);
  res={success:true,query:oq,intent,date,summaryText:`${date} 請假狀況：共 ${fr.length} 人`+(lt?`（${lt}）`:'')+`，倉別：${wh.join(', ')}\n`+detail,detailText:detail,totals:{totalLeave:fr.length,byWarehouse:{},byLeaveType:{}},rows:fr};
  for(const r of fr){res.totals.byWarehouse[r.warehouse]=(res.totals.byWarehouse[r.warehouse]||0)+1;const t=r.leaveType||'未分類';res.totals.byLeaveType[t]=(res.totals.byLeaveType[t]||0)+1;}break;}
case'sick_leave_stats':{const sr=df.filter(r=>(r.leaveType||r.attendanceStatus||'').trim()==='病假');
  const detail=buildDetail(sr);
  res={success:true,query:oq,intent,date,summaryText:`${date} 病假統計：共 ${sr.length} 人，倉別：${wh.join(', ')}\n`+detail,detailText:detail,totals:{totalSickLeave:sr.length,byWarehouse:{}},rows:sr};
  for(const r of sr)res.totals.byWarehouse[r.warehouse]=(res.totals.byWarehouse[r.warehouse]||0)+1;break;}
case'leave_stats':{const lr=df.filter(r=>{const s=r.attendanceStatus||r.leaveType||'';return s&&!AV.includes(s);});
  const detail=buildDetail(lr);
  res={success:true,query:oq,intent,date,summaryText:`${date} 請假統計：共 ${lr.length} 人，倉別：${wh.join(', ')}`,totals:{totalLeave:lr.length,byWarehouse:{},byLeaveType:{}},rows:lr};
  for(const r of lr){res.totals.byWarehouse[r.warehouse]=(res.totals.byWarehouse[r.warehouse]||0)+1;const t=r.leaveType||'未分類';res.totals.byLeaveType[t]=(res.totals.byLeaveType[t]||0)+1;}break;}
case'attendance_detail':{res={success:true,query:oq,intent,date,summaryText:`${date} 出勤明細：共 ${df.length} 筆，倉別：${wh.join(', ')}`,totals:{totalRecords:df.length,byWarehouse:{},byDepartment:{},byShift:{}},rows:df};
  for(const r of df){res.totals.byWarehouse[r.warehouse]=(res.totals.byWarehouse[r.warehouse]||0)+1;if(r.department)res.totals.byDepartment[r.department]=(res.totals.byDepartment[r.department]||0)+1;if(r.shift)res.totals.byShift[r.shift]=(res.totals.byShift[r.shift]||0)+1;}break;}
case'attendance_stats':{const tw=df.reduce((s,r)=>s+(parseFloat(r.workHours)||0),0),to=df.reduce((s,r)=>s+(parseFloat(r.overtimeHours)||0),0);
  res={success:true,query:oq,intent,date,summaryText:`${date} 出勤統計：${df.length} 人，工時 ${tw.toFixed(1)}h，加班 ${to.toFixed(1)}h`,totals:{totalRecords:df.length,totalWorkHours:tw.toFixed(1),totalOvertimeHours:to.toFixed(1),byWarehouse:{}},rows:df};
  for(const r of df){if(!res.totals.byWarehouse[r.warehouse])res.totals.byWarehouse[r.warehouse]={count:0,wh:0,ot:0};res.totals.byWarehouse[r.warehouse].count++;res.totals.byWarehouse[r.warehouse].wh+=parseFloat(r.workHours)||0;res.totals.byWarehouse[r.warehouse].ot+=parseFloat(r.overtimeHours)||0;}
  for(const w of Object.keys(res.totals.byWarehouse)){res.totals.byWarehouse[w].wh=res.totals.byWarehouse[w].wh.toFixed(1);res.totals.byWarehouse[w].ot=res.totals.byWarehouse[w].ot.toFixed(1);}break;}
default:res={success:false,query:oq,error:`無法識別意圖：${intent}`};}
if(warnings?.length)res.warnings=warnings;if(errors?.length){res.errors=errors;if(res.rows?.length===0){res.success=false;res.summaryText='部分倉別讀取失敗';}}
if(res.rows?.length===0&&res.success){res.success=false;res.summaryText=`${date} 查無資料（${wh.join(', ')}）`;}
res.emailReady=true;res.emailSubject=`[出勤報表] ${date} ${intent}`;res.emailBody=res.summaryText||'';
return [{json:res}];
